import React, { useState } from "react";

function App() {
  const [songs, setSongs] = useState([]);

  const musicData = {
    Happy: ["🎵 Shape of You", "🎵 Believer", "🎵 Perfect"],
    Sad: ["🎵 Someone Like You", "🎵 Let Her Go", "🎵 Fix You"],
    Relaxed: ["🎵 Closer", "🎵 Memories", "🎵 Photograph"]
  };

  const showSongs = (mood) => {
    setSongs(musicData[mood]);
  };

  return (
    <div
      style={{
        background: "linear-gradient(to right, #667eea, #764ba2)",
        minHeight: "100vh",
        padding: "30px",
        textAlign: "center",
      }}
    >
      <div
        style={{
          backgroundColor: "white",
          width: "500px",
          margin: "auto",
          padding: "25px",
          borderRadius: "15px",
          boxShadow: "0 4px 15px rgba(0,0,0,0.3)",
        }}
      >
        <h1 style={{ color: "#764ba2" }}>
          🎧 Mood-Based Music Recommender
        </h1>

        <p>Select your mood and get song recommendations!</p>

        <button
          onClick={() => showSongs("Happy")}
          style={{
            backgroundColor: "#28a745",
            color: "white",
            padding: "10px 20px",
            margin: "10px",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
          }}
        >
          😊 Happy
        </button>

        <button
          onClick={() => showSongs("Sad")}
          style={{
            backgroundColor: "#dc3545",
            color: "white",
            padding: "10px 20px",
            margin: "10px",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
          }}
        >
          😢 Sad
        </button>

        <button
          onClick={() => showSongs("Relaxed")}
          style={{
            backgroundColor: "#007bff",
            color: "white",
            padding: "10px 20px",
            margin: "10px",
            border: "none",
            borderRadius: "8px",
            cursor: "pointer",
          }}
        >
          😌 Relaxed
        </button>

        <h2 style={{ marginTop: "20px" }}>
          🎶 Recommended Songs
        </h2>

        <ul style={{ listStyle: "none", padding: 0 }}>
          {songs.map((song, index) => (
            <li
              key={index}
              style={{
                backgroundColor: "#f4f4f4",
                margin: "8px",
                padding: "10px",
                borderRadius: "8px",
                fontSize: "18px",
              }}
            >
              {song}
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

export default App;
